     4вҶ’export type TransactionGainType = 'CARD' | 'TAG' | 'CASHBACK';
     5вҶ’
     6вҶ’export const getTransactionGainType = (
     7вҶ’  transaction: MyOrdersDetailProps['transaction'],
     8вҶ’): TransactionGainType => {
     9вҶ’  if (!transaction) return 'CARD';
    10вҶ’
    11вҶ’  const provider = transaction.details?.provider?.toLowerCase() || '';
    12вҶ’
    13вҶ’  if (provider.includes('cashback')) {
    14вҶ’    return 'CASHBACK';
    15вҶ’  }
    16вҶ’
    17вҶ’  const icon = transaction.icon?.toLowerCase() || '';
    18вҶ’  const description = transaction.description?.toLowerCase() || '';
    19вҶ’
    20вҶ’  const tagIndicators = [
    21вҶ’    'tag',
    22вҶ’    'pedГЎgio',
    23вҶ’    'pedagio',
    24вҶ’    'estacionamento',
    25вҶ’    'abastecimento',
    26вҶ’    'abastece',
    27вҶ’    'drive',
    28вҶ’    'lava',
    29вҶ’    'rГЎpido',
    30вҶ’  ];
    31вҶ’
    32вҶ’  const isTag = tagIndicators.some(
    33вҶ’    indicator =>
    34вҶ’      icon.includes(indicator) ||
    35вҶ’      description.includes(indicator) ||
    36вҶ’      provider.includes(indicator),
    37вҶ’  );
    38вҶ’
    39вҶ’  return isTag ? 'TAG' : 'CARD';
    40вҶ’};
