    42вҶ’export const getFormattedPointsValue = (
    43вҶ’  amount: number,
    44вҶ’  type: TransactionType,
    45вҶ’): string => {
    46вҶ’  const prefix = type === 'CREDIT' || type === 'REFUNDED' ? '+ ' : '- ';
    47вҶ’  const label = Math.abs(amount) === 1 ? 'ponto' : 'pontos';
    48вҶ’  return `${prefix}${Math.abs(amount).toLocaleString('pt-BR')} ${label}`;
    49вҶ’};
