    51вҶ’export const getFormattedHighlightText = (
    52вҶ’  date: string,
    53вҶ’  _gainType: TransactionGainType,
    54вҶ’  momentInstance: typeof moment,
    55вҶ’): string => {
    56вҶ’  const transactionDate = momentInstance(date);
    57вҶ’  const day = transactionDate.format('DD');
    58вҶ’  const month = transactionDate.format('MMM').toLowerCase();
    59вҶ’  const year = transactionDate.format('YYYY');
    60вҶ’  const time = transactionDate.format('HH:mm');
    61вҶ’
    62вҶ’  return `Pedido feito em ${day} ${month} ${year} Г s ${time}`;
    63вҶ’};
    64вҶ’
    65вҶ’export const getFormattedPointsValueForMarketplace = (
    66вҶ’  valuePoints: number,
    67вҶ’): string => {
    68вҶ’  const absValue = Math.abs(valuePoints);
    69вҶ’  const label = absValue === 1 ? 'ponto' : 'pontos';
    70вҶ’  return `${absValue.toLocaleString('pt-BR')} ${label}`;
    71вҶ’};
