    73вҶ’export const getPaymentTypeLabel = (paymentType: string): string => {
    74вҶ’  const labels: Record<string, string> = {
    75вҶ’    POINTS: 'Pontos',
    76вҶ’    CARD: 'CartГЈo',
    77вҶ’    PIX: 'PIX',
    78вҶ’  };
    79вҶ’  return labels[paymentType] || paymentType;
    80вҶ’};
