    82вҶ’export const getMarketplaceTitle = (
    83вҶ’  transaction: MyOrdersDetailProps['transaction'],
    84вҶ’): string | null => {
    85вҶ’  if (!transaction?.marketplace?.orders) return null;
    86вҶ’
    87вҶ’  const allItems: Array<{ name: string }> = [];
    88вҶ’  transaction.marketplace.orders.forEach(order => {
    89вҶ’    if (order.items) {
    90вҶ’      allItems.push(...order.items);
    91вҶ’    }
    92вҶ’  });
    93вҶ’
    94вҶ’  if (allItems.length === 0) return null;
    95вҶ’  if (allItems.length === 1) return allItems[0].name;
    96вҶ’
    97вҶ’  const firstItemName = allItems[0].name;
    98вҶ’  const secondItemFirstWord = allItems[1].name.split(' ')[0];
    99вҶ’
   100вҶ’  if (allItems.length === 2) {
   101вҶ’    return `${firstItemName} e ${secondItemFirstWord}`;
   102вҶ’  }
   103вҶ’
   104вҶ’  const remainingCount = allItems.length - 2;
   105вҶ’  return `${firstItemName}, ${secondItemFirstWord} e outros ${remainingCount}`;
   106вҶ’};
