   108вҶ’export const getCleanedImageUrl = (
   109вҶ’  url: string | undefined,
   110вҶ’): string | undefined => {
   111вҶ’  if (!url) return undefined;
   112вҶ’
   113вҶ’  let cleanedUrl = url.trim();
   114вҶ’
   115вҶ’  if (cleanedUrl.startsWith('imageUrl:')) {
   116вҶ’    cleanedUrl = cleanedUrl.replace(/^imageUrl:/i, '');
   117вҶ’  }
   118вҶ’
   119вҶ’  if (cleanedUrl.startsWith('http://') || cleanedUrl.startsWith('https://')) {
   120вҶ’    return cleanedUrl;
   121вҶ’  }
   122вҶ’
   123вҶ’  return undefined;
   124вҶ’};
